class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
        const val SCHEME = "myapp"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIntent(it) }
    }

    private fun handleIntent(intent: Intent) {
        val uri = intent.data
        if (uri == null || uri.scheme != SCHEME) {
            Log.w(TAG, "Invalid deep link: $uri")
            Toast.makeText(this, "Invalid link", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        Log.d(TAG, "Handling deep link: $uri")

        val deepLinkRoute = DeepLinkParser.parse(uri)

        if (deepLinkRoute != null) {
            DeepLinkNavigator.navigate(this, deepLinkRoute)
        } else {
            Log.w(TAG, "Unrecognized deep link path: $uri")
            Toast.makeText(this, "Unknown link destination", Toast.LENGTH_SHORT).show()
            // Navigate to main activity as fallback
            DeepLinkNavigator.navigateToMain(this)
        }

        finish()
    }
}

// Sealed class representing all supported deep link routes
sealed class DeepLinkRoute {
    data class Profile(val userId: String) : DeepLinkRoute()
    data class PaymentConfirm(
        val transactionId: String? = null,
        val amount: String? = null
    ) : DeepLinkRoute()
    data class Product(val productId: String) : DeepLinkRoute()
    data class Campaign(
        val campaignId: String?,
        val source: String?
    ) : DeepLinkRoute()
    object Home : DeepLinkRoute()
    object Settings : DeepLinkRoute()
}

// Parser that converts URIs into DeepLinkRoute objects
object DeepLinkParser {

    private const val TAG = "DeepLinkParser"

    fun parse(uri: Uri): DeepLinkRoute? {
        val pathSegments = uri.pathSegments
        val host = uri.host

        Log.d(TAG, "Parsing URI - host: $host, pathSegments: $pathSegments, query: ${uri.query}")

        return when (host) {
            "profile" -> parseProfile(pathSegments, uri)
            "payment" -> parsePayment(pathSegments, uri)
            "product" -> parseProduct(pathSegments, uri)
            "campaign" -> parseCampaign(uri)
            "home" -> DeepLinkRoute.Home
            "settings" -> DeepLinkRoute.Settings
            else -> null
        }
    }

    // myapp://profile/123 or myapp://profile?id=123
    private fun parseProfile(pathSegments: List<String>, uri: Uri): DeepLinkRoute? {
        val userId = pathSegments.firstOrNull() ?: uri.getQueryParameter("id")
        return if (userId != null) {
            DeepLinkRoute.Profile(userId)
        } else {
            Log.w(TAG, "Profile deep link missing user ID")
            null
        }
    }

    // myapp://payment/confirm or myapp://payment/confirm?transaction_id=abc&amount=50.00
    private fun parsePayment(pathSegments: List<String>, uri: Uri): DeepLinkRoute? {
        return when (pathSegments.firstOrNull()) {
            "confirm" -> DeepLinkRoute.PaymentConfirm(
                transactionId = uri.getQueryParameter("transaction_id"),
                amount = uri.getQueryParameter("amount")
            )
            else -> {
                Log.w(TAG, "Unknown payment action: ${pathSegments.firstOrNull()}")
                null
            }
        }
    }

    // myapp://product/456
    private fun parseProduct(pathSegments: List<String>, uri: Uri): DeepLinkRoute? {
        val productId = pathSegments.firstOrNull() ?: uri.getQueryParameter("id")
        return if (productId != null) {
            DeepLinkRoute.Product(productId)
        } else {
            Log.w(TAG, "Product deep link missing product ID")
            null
        }
    }

    // myapp://campaign?id=summer2024&source=email
    private fun parseCampaign(uri: Uri): DeepLinkRoute {
        return DeepLinkRoute.Campaign(
            campaignId = uri.getQueryParameter("id"),
            source = uri.getQueryParameter("source")
        )
    }
}

// Navigator that launches the appropriate Activity based on the route
object DeepLinkNavigator {

    private const val TAG = "DeepLinkNavigator"

    fun navigate(activity: Activity, route: DeepLinkRoute) {
        Log.d(TAG, "Navigating to route: $route")

        val intent = when (route) {
            is DeepLinkRoute.Profile -> {
                Intent(activity, ProfileActivity::class.java).apply {
                    putExtra(ProfileActivity.EXTRA_USER_ID, route.userId)
                }
            }
            is DeepLinkRoute.PaymentConfirm -> {
                Intent(activity, PaymentConfirmActivity::class.java).apply {
                    putExtra(PaymentConfirmActivity.EXTRA_TRANSACTION_ID, route.transactionId)
                    putExtra(PaymentConfirmActivity.EXTRA_AMOUNT, route.amount)
                }
            }
            is DeepLinkRoute.Product -> {
                Intent(activity, ProductActivity::class.java).apply {
                    putExtra(ProductActivity.EXTRA_PRODUCT_ID, route.productId)
                }
            }
            is DeepLinkRoute.Campaign -> {
                // Track campaign analytics
                CampaignTracker.trackCampaignOpen(route.campaignId, route.source)
                Intent(activity, MainActivity::class.java).apply {
                    putExtra(MainActivity.EXTRA_CAMPAIGN_ID, route.campaignId)
                    putExtra(MainActivity.EXTRA_CAMPAIGN_SOURCE, route.source)
                }
            }
            is DeepLinkRoute.Home -> {
                Intent(activity, MainActivity::class.java)
            }
            is DeepLinkRoute.Settings -> {
                Intent(activity, SettingsActivity::class.java)
            }
        }

        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        activity.startActivity(intent)
    }

    fun navigateToMain(activity: Activity) {
        val intent = Intent(activity, MainActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        activity.startActivity(intent)
    }
}

