// Utility to create deep link URIs programmatically (useful for push notifications)
object DeepLinkBuilder {

    fun buildProfileLink(userId: String): Uri {
        return Uri.parse("myapp://profile/$userId")
    }

    fun buildPaymentConfirmLink(transactionId: String? = null, amount: String? = null): Uri {
        val builder = Uri.Builder()
            .scheme("myapp")
            .authority("payment")
            .appendPath("confirm")
        transactionId?.let { builder.appendQueryParameter("transaction_id", it) }
        amount?.let { builder.appendQueryParameter("amount", it) }
        return builder.build()
    }

    fun buildProductLink(productId: String): Uri {
        return Uri.parse("myapp://product/$productId")
    }

    fun buildCampaignLink(campaignId: String, source: String): Uri {
        return Uri.Builder()
            .scheme("myapp")
            .authority("campaign")
            .appendQueryParameter("id", campaignId)
            .appendQueryParameter("source", source)
            .build()
    }

    fun buildHomeLink(): Uri {
        return Uri.parse("myapp://home")
    }

    fun buildSettingsLink(): Uri {
        return Uri.parse("myapp://settings")
    }
}